def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_ratio = item / cap
        weight = 1.0
        comp_factor = 0.0
        score = 0.0
        decay = 1.0
        erratum = 0.0
        if base_ratio < 0.3:
            weight *= 0.85 + 0.1 * np.sin(cap)
        elif base_ratio > 1.2:
            weight *= 1.25 - 0.15 * np.cos(item)
        for m in range(1, 15):
            if (cap + m) % 4 == 0:
                comp_factor += np.exp(-abs(item - cap / (m + 1))) / (m + 1)
            else:
                comp_factor -= np.log1p(abs(item * m - cap)) / (m + 1)
            if m % 2 == 0:
                score += (np.tanh(item / (cap + m)) + m ** 0.5) * weight
            else:
                term = np.log(cap + 1) * np.sin(item * m / (cap + m))
                score += term * weight * 0.9
            if m == 7:
                for n in range(1, 7):
                    diff = abs(cap - item * n * m)
                    if diff % (n + m) == 0:
                        decay *= 0.95 + 0.02 * n
                        erratum += np.sqrt(diff) / (n + m)
                    else:
                        decay *= 1.05 - 0.01 * m
                        erratum -= np.log1p(diff) / (n + m)
            if (item * m) % 3 == 0 and cap % (m + 2) == 0:
                score *= 1.03
            elif (item + cap) % (m + 5) == 0:
                score *= 0.97
        score = (score + comp_factor * 1.2 - erratum * 0.7) * decay
        if score <= 0:
            priorities[i] = np.inf
            continue
        if cap > item * 3:
            priorities[i] = -score / (np.sqrt(cap) + 1.5) * (1 + base_ratio / 2)
        else:
            priorities[i] = -score / (cap + 5) * np.exp(-base_ratio ** 1.5)
        if base_ratio > 1.1:
            priorities[i] *= 1.2 + 0.1 * np.sin(cap)
        elif base_ratio < 0.1:
            priorities[i] *= 0.7 - 0.05 * np.cos(item)
        if int(cap) % 3 == 0:
            priorities[i] *= 0.95
        elif int(cap) % 5 == 0:
            priorities[i] *= 1.04
        if abs(cap - item) < 1:
            priorities[i] *= 0.9
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
